import React from 'react';
import { useConversation } from './hooks/useConversation';
import ChatBubble from './components/ChatBubble';
import InputArea from './components/InputArea';

function App() {
  // Pulling the logic from your custom hook
  const { messages, isTyping, currentStep, handleUserAnswer } = useConversation();

  return (
    <div className="flex flex-col h-screen bg-slate-50 max-w-md mx-auto border-x shadow-xl">
      {/* Header - Sets the professional tone for the Doctor */}
      <header className="p-6 bg-white border-b text-center shadow-sm">
        <h1 className="font-bold text-slate-800 text-xl">Counseling Assistant</h1>
        <p className="text-xs text-slate-500 uppercase tracking-widest mt-1">NIMHANS Clinical Proforma</p>
      </header>

      {/* Chat History - Where the 'Conversation' happens */}
      <div className="flex-1 overflow-y-auto p-4 space-y-2 scroll-smooth bg-[#f8fafc]">
        {messages.map((m, index) => (
          <ChatBubble key={index} message={m.text} sender={m.sender} />
        ))}
        
        {/* Typing Indicator - This builds the 'Counselor Vibe' */}
        {isTyping && (
          <div className="flex justify-start mb-4 animate-pulse">
            <div className="bg-white p-4 rounded-2xl rounded-tl-none shadow-sm text-slate-400 text-sm">
              Counselor is thinking...
            </div>
          </div>
        )}
      </div>

      {/* Input Area - Changes dynamically based on the NIMHANS step */}
      <div className="bg-white shadow-lg">
        <InputArea 
          currentStep={currentStep} 
          onSendMessage={handleUserAnswer} 
          isTyping={isTyping} 
        />
      </div>
    </div>
  );
}

export default App;
